class Solution {
    public String crackSafe(int n, int k) {
        int[] dp = new int[k + 1];
        for (int i = 0; i <= k; i++) {
            dp[i] = i;
        }
        for (int i = n - 1; i >= 0; i--) {
            for (int j = k; j >= 0; j--) {
                dp[i + 1] = Math.min(dp[i + 1], dp[i] + 1);
            }
        }
        return String.valueOf(dp[k]);
    }
}
```

